const WithBackground = ({
  bgcolor: bgcolorProp,
  loading,
  fetching,
}: WithBackgroundProps) => {
  const { palette } = useTheme();
  const BackgroundColors: Record<"primary" | "secondary", string> = {
    primary: palette.primary.main,
    secondary: palette.secondary.main,
  };
  const bgcolor = BackgroundColors[bgcolorProp];
  const selectColor = palette.getContrastText(bgcolor);

  return (
    <Box bgcolor={bgcolor} padding={3}>
      <Autocomplete
        label="Car model"
        options={options}
        color={selectColor}
        loading={loading}
        fetching={fetching}
      />
    </Box>
  );
};

const WithSlotPropsCustomization = () => {
    // Custom styled text field wrapper
    const CustomFieldWrapper = styled(Box)(({ theme }) => ({
      "& .MuiTextField-root": {
        "& .MuiOutlinedInput-root": {
          backgroundColor: theme.palette.primary.light,
          borderRadius: 16,
          "& fieldset": {
            borderColor: theme.palette.primary.main,
            borderWidth: 2,
          },
          "&:hover fieldset": {
            borderColor: theme.palette.primary.dark,
          },
          "&.Mui-focused fieldset": {
            borderColor: theme.palette.primary.dark,
          },
        },
        "& .MuiInputLabel-root": {
          color: theme.palette.primary.main,
          fontWeight: 600,
        },
      },
    }));

    return (
        <CustomFieldWrapper>
            <Autocomplete
                label="Car model"
                options={options}
                slotProps={{
                  autocomplete: {
                    sx: {
                      "& .MuiAutocomplete-popupIndicator": {
                        color: "primary.main",
                      },
                      "& .MuiAutocomplete-clearIndicator": {
                        color: "primary.main",
                      },
                    },
                  },
                  textField: {
                    helperText: "Customized autocomplete with styled components",
                  },
                }} />
        </CustomFieldWrapper>
    );
};

