const UsingHook = () => {
  const tableState = useRemoteDataTable({
    initialPagination: { pageSize: 10 },
    initialSorting: [{ id: "name", desc: false }],
  });

  const sortedItems = useMemo(
    () => sortItems(mockItems, tableState.sorting),
    [tableState.sorting],
  );

  const items = useMemo(
    () =>
      sortedItems.slice(
        tableState.pagination.pageIndex * tableState.pagination.pageSize,
        tableState.pagination.pageIndex * tableState.pagination.pageSize +
          tableState.pagination.pageSize,
      ),
    [tableState.pagination, sortedItems],
  );

  return (
    <RemoteDataTable
      data={items}
      columns={mockColumnsFull}
      rowCount={mockItems.length}
      pagination={tableState.pagination}
      onPaginationChange={tableState.onPaginationChange}
      sorting={tableState.sorting}
      onSortingChange={tableState.onSortingChange}
      pageSizeOptions={[5, 10, 25]}
      query={{
        fields: mockQueryFields,
        filters: tableState.filters,
        onFiltersChange: tableState.onFiltersChange,
        placeholder: "Filter items...",
      }}
    />
  );
};

reactDocgen.description:
A table component designed for displaying remote/server-side data with built-in
pagination, sorting, and filtering capabilities.

This component is fully controlled - all state (pagination, sorting, filters) must be
managed by the parent component. For convenience, use the `useRemoteDataTable` hook
to manage this state.

@example
```tsx
const tableState = useRemoteDataTable({
  initialPagination: { pageSize: 25 }
});

<RemoteDataTable
  data={items}
  columns={columns}
  {...tableState}
  query={{
    fields: queryFields,
    filters: tableState.filters,
    onFiltersChange: tableState.onFiltersChange
  }}
/>
```

